1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty array for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should return empty array for single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should return empty array for two live cells (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep all cells alive in a block (still life)", () => {
15	    expect(nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]])).toEqual([[0, 0], [1, 0], [0, 1], [1, 1]]);
16	  });
17	  it("should reproduce a dead cell with exactly 3 live neighbors", () => {
18	    expect(nextGeneration([[0, 0], [1, 0], [0, 1]])).toContainEqual([1, 1]);
19	  });
20	  it.todo("should transform blinker from vertical to horizontal");
21	  it.todo("should transform blinker from horizontal back to vertical");
22	});
23

1	type Cell = [number, number];
2	
3	const countNeighbors = (cell: Cell, cells: Cell[]): number =>
4	  cells.filter(
5	    ([cx, cy]) =>
6	      Math.abs(cx - cell[0]) <= 1 &&
7	      Math.abs(cy - cell[1]) <= 1 &&
8	      !(cx === cell[0] && cy === cell[1])
9	  ).length;
10	
11	const neighborPositions = (cell: Cell): Cell[] => {
12	  const [x, y] = cell;
13	  const candidates: Cell[] = [];
14	  for (let dx = -1; dx <= 1; dx++) {
15	    for (let dy = -1; dy <= 1; dy++) {
16	      if (dx !== 0 || dy !== 0) {
17	        candidates.push([x + dx, y + dy]);
18	      }
19	    }
20	  }
21	  return candidates;
22	};
23	
24	export function nextGeneration(cells: Cell[]): Cell[] {
25	  const survivors = cells.filter((cell) => {
26	    const neighborCount = countNeighbors(cell, cells);
27	    return neighborCount === 2 || neighborCount === 3;
28	  });
29	
30	  const deadCandidates = cells
31	    .flatMap(neighborPositions)
32	    .filter(([cx, cy], index, all) =>
33	      !cells.some(([lx, ly]) => lx === cx && ly === cy) &&
34	      all.findIndex(([ax, ay]) => ax === cx && ay === cy) === index
35	    );
36	
37	  const born = deadCandidates.filter(
38	    (cell) => countNeighbors(cell, cells) === 3
39	  );
40	
41	  return [...survivors, ...born];
42	}
43

